// Flatten the LLM qualification and re-attach the original lead into one clean item.
// Parse defensively so a malformed response degrades gracefully instead of throwing.
const lead = $('Lead Webhook').item.json.body ?? {};

let q = $json.message?.content
  ?? $json.choices?.[0]?.message?.content
  ?? $json;
if (typeof q === 'string') {
  try { q = JSON.parse(q); } catch (e) { q = {}; }
}

const score = Number(q.score);
const validScore = Number.isFinite(score) ? Math.max(1, Math.min(10, Math.round(score))) : 0;
let tier = String(q.tier ?? '').toLowerCase();
if (!['hot', 'warm', 'cold'].includes(tier)) {
  tier = validScore >= 8 ? 'hot' : validScore >= 5 ? 'warm' : 'cold';
}

return {
  json: {
    name: lead.name ?? '',
    email: lead.email ?? '',
    company: lead.company ?? '',
    website: lead.website ?? '',
    message: lead.message ?? '',
    score: validScore,
    tier,
    reasoning: q.reasoning ?? '',
    qualified_at: new Date().toISOString(),
  },
};
